const body = $json.body || {};

const batchCount = Number(body.batchCount || 2);
const batchSize = Number(body.batchSize || 5);

const batches = [];
for (let i = 1; i <= batchCount; i++) {
  batches.push({
    json: {
      batchNumber: i,
      batchSize
    }
  });
}

return batches;

