{
  model: "llama3.2",
  prompt:
    "Generate exactly " + $json.batchSize + " realistic task records.\n" +
    "Return one compact JSON object after another.\n" +
    "Do not wrap them in an array.\n" +
    "Do not add explanation text.\n" +
    "Each object must contain: title, description, status, priority, dueDate.\n" +
    "status must be one of OPEN, IN_PROGRESS, DONE, BLOCKED.\n" +
    "priority must be one of LOW, MEDIUM, HIGH.\n" +
    "dueDate must be YYYY-MM-DD.\n" +
    "Batch number: " + $json.batchNumber + ".",
  stream: false
}
}}

parameters.jsCode:
const items = $input.all();

return items.map(item => {
  const raw = item.json.response || "";
  let text = raw.trim();

  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const matches = text.match(/\{[^{}]*\}/g);

  if (!matches || matches.length === 0) {
    throw new Error("No JSON objects found in Ollama response:\n" + raw);
  }

  const tasks = [];

  for (const m of matches) {
    let task;
    try {
      task = JSON.parse(m);
    } catch (e) {
      continue;
    }

    if (task.dueDate && typeof task.dueDate === "string") {
      task.dueDate = task.dueDate.slice(0, 10);
    }

    const cleaned = {
      title: task.title,
      description: task.description ?? "",
      status: task.status,
      priority: task.priority,
    };

    if (task.dueDate) cleaned.dueDate = task.dueDate;

    if (
      cleaned.title &&
      ["OPEN", "IN_PROGRESS", "DONE", "BLOCKED"].includes(cleaned.status) &&
      ["LOW", "MEDIUM", "HIGH"].includes(cleaned.priority)
    ) {
      tasks.push(cleaned);
    }
  }

  return {
    json: {
      batchCount: tasks.length,
      tasks
    }
  };
});
